        Directory.CreateDirectory(Path.Combine(root, "src", "sub"));
        await File.WriteAllTextAsync(Path.Combine(root, "src", "a.txt"), "x");
        await File.WriteAllTextAsync(Path.Combine(root, "src", "sub", "b.txt"), "y");

